import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer';
import { TradeOpenParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/TradeOpenParser';

export class TradeOpenEvent extends MessageEvent implements IMessageEvent
{
constructor(callback: Function)
{
super(callback, TradeOpenParser);
}

public getParser(): TradeOpenParser
{
return this.parser as TradeOpenParser;
}
}